import React from "react";

function Home() {
  const displayname = localStorage.getItem("name") || "User";

  return (
    <>
      <div className="container">
        <div className="col-6">
          <h2 className="mt-5">Welcome, {displayname} to My Portfolio</h2>
          <div className="row">
            <h1 className="mt-5">Hello, My name is Prathmesh Nalawade</h1>
            <p>I'm BCS Graduate Student,</p>
            <p>I certified in Full MERN Stack Web Development.</p>
          </div>
        </div>
        <div className="col-6"></div>
      </div>
    </>
  );
}

export default Home;
